Use greedy best-cost insertion across all feasible vehicles, evaluating both non-empty and empty assigns via cost delta, with fallback to first-available if none improve cost.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	for jj := range oris {
		bestAssignIdx := -1
		bestCostDelta := 1e308
		inserted := false

		ori := oris[jj]
		des := dess[jj]
		shipID := total_ship + jj

		// Try existing non-empty assigns first
		for ii := 0; ii < dispatch.AssignsLen; ii++ {
			assignCopy := dispatch.Assigns[ii]
			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				costDelta := assignCopy.Cost - dispatch.Assigns[ii].Cost
				if costDelta >= 0 && costDelta < bestCostDelta {
					bestCostDelta = costDelta
					bestAssignIdx = ii
				}
			}
		}

		// Also consider using a new empty assign if available and beneficial compared to worst feasible
		if dispatch.AssignsLen < MAXASSIGNS {
			emptyIdx := dispatch.AssignsLen
			assignCopy := dispatch.Assigns[emptyIdx]
			ok := assignCopy.AddShip(shipID, ori, des)
			if ok {
				assignCopy.GenRoute()
				costDelta := assignCopy.Cost
				// Empty assign cost may be lower than adding to congested ones
				if costDelta < bestCostDelta || bestAssignIdx == -1 {
					bestCostDelta = costDelta
					bestAssignIdx = emptyIdx
				}
			}
		}

		// Perform insertion at chosen best index
		if bestAssignIdx != -1 {
			ok := dispatch.Assigns[bestAssignIdx].AddShip(shipID, ori, des)
			if ok {
				dispatch.Assigns[bestAssignIdx].GenRoute()
				if bestAssignIdx >= dispatch.AssignsLen {
					dispatch.AssignsLen++
				}
				inserted = true
			}
		}

		// Fallback: try all assigns sequentially until first success
		if !inserted {
			fallbackInserted := false
			for ii := 0; ii <= dispatch.AssignsLen && ii < MAXASSIGNS; ii++ {
				if ii == dispatch.AssignsLen && ii < MAXASSIGNS {
					// Trying a brand-new assign
					ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
					if ok {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							dispatch.AssignsLen++
							fallbackInserted = true
							break
						} else {
							dispatch.Assigns[ii].RemoveShip(shipID)
							dispatch.Assigns[ii].GenRoute()
						}
					}
				} else if ii < dispatch.AssignsLen {
					ok := dispatch.Assigns[ii].AddShip(shipID, ori, des)
					if ok {
						dispatch.Assigns[ii].GenRoute()
						if dispatch.Assigns[ii].Cost >= 0 {
							fallbackInserted = true
							break
						} else {
							dispatch.Assigns[ii].RemoveShip(shipID)
							dispatch.Assigns[ii].GenRoute()
						}
					}
				}
			}
			if !fallbackInserted && dispatch.AssignsLen < MAXASSIGNS {
				ok := dispatch.Assigns[dispatch.AssignsLen].AddShip(shipID, ori, des)
				if ok {
					dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					if dispatch.Assigns[dispatch.AssignsLen].Cost >= 0 {
						dispatch.AssignsLen++
					} else {
						dispatch.Assigns[dispatch.AssignsLen].RemoveShip(shipID)
						dispatch.Assigns[dispatch.AssignsLen].GenRoute()
					}
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

