Greedy insertion with time window feasibility check, fallback to empty assign creation if all existing assigns fail, while preserving original dispatch's valid assignments and shuffling candidate order for better exploration.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	orderIndices := make([]int, len(oris))
	for i := range orderIndices {
		orderIndices[i] = i
	}
	rand.Shuffle(len(orderIndices), func(i, j int) {
		orderIndices[i], orderIndices[j] = orderIndices[j], orderIndices[i]
	})
	assignIndices := make([]int, dispatch.AssignsLen)
	for i := range assignIndices {
		assignIndices[i] = i
	}
	insertedCount := 0
	for _, idx := range orderIndices {
		shippedID := total_ship + idx
		ori := oris[idx]
		des := dess[idx]
		bestAssignIdx := -1
		bestDelta := math.MaxFloat64
		bestCostBackup := 0.0
		for _, ai := range assignIndices {
			costBefore := dispatch.Assigns[ai].Cost
			ok := dispatch.Assigns[ai].AddShip(shippedID, ori, des)
			if ok {
				dispatch.Assigns[ai].GenRoute()
				if dispatch.Assigns[ai].Cost >= 0 {
					delta := dispatch.Assigns[ai].Cost - costBefore
					if delta < bestDelta {
						bestDelta = delta
						bestAssignIdx = ai
						bestCostBackup = dispatch.Assigns[ai].Cost
					}
				}
				dispatch.Assigns[ai].RemoveShip(shippedID)
				dispatch.Assigns[ai].GenRoute()
			}
		}
		if bestAssignIdx != -1 {
			dispatch.Assigns[bestAssignIdx].AddShip(shippedID, ori, des)
			dispatch.Assigns[bestAssignIdx].GenRoute()
			insertedCount++
		} else {
			newIdx := dispatch.AssignsLen
			if newIdx < MAXASSIGNS {
				dispatch.Assigns[newIdx].AddShip(shippedID, ori, des)
				dispatch.Assigns[newIdx].GenRoute()
				if dispatch.Assigns[newIdx].Cost >= 0 {
					dispatch.AssignsLen++
					insertedCount++
				} else {
					dispatch.Assigns[newIdx].RemoveShip(shippedID)
					dispatch.Assigns[newIdx].GenRoute()
				}
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

